import React, { useCallback, useEffect, useState } from 'react';
import { INVOICE_DRAFT_PREFIX } from '../constants/localStorageKeys';
import { useAuth } from '../contexts/AuthContext';
import { useBeforeUnloadGuard } from '../hooks/useBeforeUnloadGuard';
import { useConnectionToast } from '../contexts/ConnectionToastContext';
import { ApiError } from '../utils/api';
import { formatCurrency as _formatCurrency, formatQuickBooksDate as _formatQuickBooksDate } from '../utils/formatters';
import { nowDate } from '../utils/dateDefaults';
import {
  Box,
  Button,
  CircularProgress,
  IconButton,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableFooter,
  TableHead,
  TableRow,
  TextField,
  Tooltip,
  Typography,
} from '@mui/material';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import DownloadIcon from '@mui/icons-material/Download';
import EmailIcon from '@mui/icons-material/Email';
import { FullScreenModal } from './modals/FullScreenModal';

type _Icons = typeof ArrowBackIcon | typeof ArrowForwardIcon |
  typeof DownloadIcon | typeof EmailIcon;

// ── API types (camelCase from server) ─────────────────────────────────────────

export interface InvoiceSummary {
  id: string;
  docNumber: string;
  customerName: string;
  email: string | null;
  balance: number;
  totalAmt: number;
  dueDate: string | null;
  txnDate: string | null;
}

export interface InvoiceLine {
  description?: string;
  qty?: number | null;
  unitPrice?: number | null;
  amount?: number;
  detailType?: string;
}

export interface InvoiceDetail extends InvoiceSummary {
  email: string | null;
  syncToken: string;
  memo: string | null;
  lines: InvoiceLine[];
}

// ── Draft persistence (localStorage) ──────────────────────────────────────────

interface InvoiceDraft {
  due: string;
  email: string;
  memo: string;
}

export function loadDraft(invId: string, userId?: string | number): InvoiceDraft | null {
  if (!userId) return null;
  try {
    const k = `${INVOICE_DRAFT_PREFIX}${userId}`;
    const raw = localStorage.getItem(k);
    if (!raw) return null;
    const map = JSON.parse(raw) as Record<string, InvoiceDraft>;
    return map[invId] ?? null;
  } catch {
    return null;
  }
}

export function saveDraft(invId: string, draft: InvoiceDraft, userId?: string | number) {
  if (!userId) return;
  try {
    const k = `${INVOICE_DRAFT_PREFIX}${userId}`;
    const raw = localStorage.getItem(k);
    const map: Record<string, InvoiceDraft> = raw ? JSON.parse(raw) : {};
    map[invId] = draft;
    localStorage.setItem(k, JSON.stringify(map));
  } catch { /* ignore */ }
}

export function clearDraft(invId: string, userId?: string | number) {
  if (!userId) return;
  try {
    const k = `${INVOICE_DRAFT_PREFIX}${userId}`;
    const raw = localStorage.getItem(k);
    if (!raw) return;
    const map: Record<string, InvoiceDraft> = JSON.parse(raw);
    delete map[invId];
    localStorage.setItem(k, JSON.stringify(map));
  } catch { /* ignore */ }
}

// ── Formatting helpers (re-exported from shared utils) ─────────────────────────

export function formatCurrency(amount?: number | string | null): string {
  return _formatCurrency(amount);
}

export function fmtDate(iso?: string | null): string {
  return _formatQuickBooksDate(iso) || '—';
}

export function invoiceStatus(inv: Pick<InvoiceSummary, 'balance' | 'totalAmt' | 'dueDate'>): 'paid' | 'overdue' | 'partial' | 'open' {
  const balance = Number(inv.balance ?? 0);
  const total   = Number(inv.totalAmt ?? 0);
  if (balance <= 0) return 'paid';
  if (balance < total) return 'partial';
  if (inv.dueDate && new Date(inv.dueDate) < new Date()) return 'overdue';
  return 'open';
}

// ── Component ─────────────────────────────────────────────────────────────────

export interface InvoiceDetailDrawerProps {
  open: boolean;
  invId: string | null;
  allIds: string[];
  onClose: () => void;
  onNavigate: (id: string) => void;
  isAdmin: boolean;
  onSaved?: () => void;
}

interface EditState {
  due: string;
  email: string;
  memo: string;
  dirty: boolean;
}

export function InvoiceDetailDrawer({
  open, invId, allIds, onClose, onNavigate, isAdmin, onSaved,
}: InvoiceDetailDrawerProps) {
  const { notifyApiError } = useConnectionToast();
  const { user: _drawerUser } = useAuth();
  const _drawerUserId = _drawerUser?.id;
  const [inv, setInv]         = useState<InvoiceDetail | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState<string | null>(null);
  const [edit, setEdit]       = useState<EditState>({ due: '', email: '', memo: '', dirty: false });
  const [saveMsg, setSaveMsg] = useState<{ text: string; ok: boolean } | null>(null);
  const [sending, setSending] = useState(false);
  const [saving, setSaving]   = useState(false);

  const currentIdx = allIds.indexOf(invId ?? '');
  const hasPrev    = currentIdx > 0;
  const hasNext    = currentIdx < allIds.length - 1;

  useBeforeUnloadGuard(edit.dirty);

  useEffect(() => {
    if (!open || !invId) return;
    let cancelled = false;
    setLoading(true);
    setError(null);
    setInv(null);
    setSaveMsg(null);

    fetch(`/api/quickbooks/invoice/${invId}`)
      .then(r => r.json())
      .then(data => {
        if (cancelled) return;
        if (data.error) throw new Error(data.error);
        setInv(data);
        const draft = loadDraft(invId, _drawerUserId);
        setEdit({
          due:   draft !== null ? draft.due : (data.dueDate || nowDate()),
          email: draft?.email ?? data.email   ?? '',
          memo:  draft?.memo  ?? data.memo    ?? '',
          dirty: !!draft,
        });
        if (draft) setSaveMsg({ text: 'Unsaved changes restored', ok: true });
      })
      .catch(e => { if (!cancelled) setError((e as Error).message || 'Failed to load invoice'); })
      .finally(() => { if (!cancelled) setLoading(false); });

    return () => { cancelled = true; };
  }, [open, invId, _drawerUserId]);

  useEffect(() => {
    if (!invId || !edit.dirty) return;
    saveDraft(invId, { due: edit.due, email: edit.email, memo: edit.memo }, _drawerUserId);
  }, [invId, edit, _drawerUserId]);

  const handleClose = useCallback(() => {
    const doClose = () => {
      onClose();
      setEdit({ due: '', email: '', memo: '', dirty: false });
      setInv(null);
      setSaveMsg(null);
    };
    if (edit.dirty) {
      window.showBottomConfirm('You have unsaved changes. Discard and close?', doClose);
      return;
    }
    doClose();
  }, [edit.dirty, onClose]);

  const handleNavigate = useCallback((delta: number) => {
    const newIdx = currentIdx + delta;
    if (newIdx < 0 || newIdx >= allIds.length) return;
    const doNavigate = () => {
      setEdit({ due: '', email: '', memo: '', dirty: false });
      onNavigate(allIds[newIdx]);
    };
    if (edit.dirty) {
      window.showBottomConfirm('You have unsaved changes. Discard and continue?', doNavigate);
      return;
    }
    doNavigate();
  }, [edit.dirty, currentIdx, allIds, onNavigate]);

  const handleSave = useCallback(async () => {
    if (!inv || saving) return;
    setSaving(true);
    setSaveMsg(null);
    try {
      const res = await fetch(`/api/quickbooks/invoice/${inv.id}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          syncToken: inv.syncToken,
          dueDate:   edit.due   || null,
          memo:      edit.memo  || null,
          email:     edit.email || null,
        }),
      });
      const r = await res.json().catch(() => ({} as Record<string, unknown>));
      if (!res.ok || (r as { error?: string }).error) {
        throw new ApiError(
          (r as { error?: string }).error || `HTTP ${res.status}`,
          (r as { code?: string }).code,
          res.status,
        );
      }
      // Optimistic patch so the UI responds immediately while the re-fetch is in flight.
      setInv(prev => prev ? {
        ...prev,
        syncToken: r.syncToken,
        dueDate:   edit.due   || null,
        memo:      edit.memo  || null,
        email:     edit.email || null,
      } : prev);
      setEdit(prev => ({ ...prev, dirty: false }));
      clearDraft(inv.id, _drawerUserId);
      try {
        const bc = new BroadcastChannel('mo_invoices');
        bc.postMessage({ type: 'invoice-saved', id: inv.id });
        bc.close();
      } catch { /* BroadcastChannel not available (e.g. some test envs) */ }
      onSaved?.();
      setSaveMsg({ text: 'Saved', ok: true });
      // Re-fetch from the server to pick up any server-computed fields
      // (Balance due, Total, etc.) that the local patch doesn't cover.
      // Guard: only apply the response if the drawer is still showing the
      // same invoice — prevents a stale re-fetch from overwriting a
      // subsequently navigated-to invoice.
      const savedId = inv.id;
      fetch(`/api/quickbooks/invoice/${savedId}`)
        .then(res => res.json())
        .then(fresh => { if (!fresh.error) setInv(prev => prev?.id === savedId ? fresh : prev); })
        .catch(() => { /* non-fatal — optimistic patch is already applied */ });
    } catch (e: unknown) {
      notifyApiError('quickbooks', e, 'QuickBooks is disconnected — reconnect it to save or send invoices.');
      setSaveMsg({ text: (e as Error).message || 'Save failed', ok: false });
    } finally {
      setSaving(false);
    }
  }, [inv, saving, edit, notifyApiError, onSaved]);

  const handleSend = useCallback(async () => {
    if (!inv || sending) return;
    setSending(true);
    setSaveMsg(null);
    try {
      const res = await fetch(`/api/quickbooks/invoice/${inv.id}/send`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: edit.email || null }),
      });
      const r = await res.json().catch(() => ({} as Record<string, unknown>));
      if (!res.ok || (r as { error?: string }).error) {
        throw new ApiError(
          (r as { error?: string }).error || `HTTP ${res.status}`,
          (r as { code?: string }).code,
          res.status,
        );
      }
      setSaveMsg({ text: `Sent to ${edit.email || inv.email}`, ok: true });
    } catch (e: unknown) {
      notifyApiError('quickbooks', e, 'QuickBooks is disconnected — reconnect it to save or send invoices.');
      setSaveMsg({ text: (e as Error).message || 'Send failed', ok: false });
    } finally {
      setSending(false);
    }
  }, [inv, sending, edit.email, notifyApiError]);

  const handleDiscard = useCallback(() => {
    if (!inv) return;
    clearDraft(inv.id, _drawerUserId);
    setEdit({ due: inv.dueDate ?? '', email: inv.email ?? '', memo: inv.memo ?? '', dirty: false });
    setSaveMsg({ text: 'Changes discarded', ok: true });
  }, [inv, _drawerUserId]);

  const baseline = inv ? { due: inv.dueDate ?? '', email: inv.email ?? '', memo: inv.memo ?? '' } : null;
  const isDueChanged   = !!baseline && edit.due   !== baseline.due;
  const isEmailChanged = !!baseline && edit.email !== baseline.email;
  const isMemoChanged  = !!baseline && edit.memo  !== baseline.memo;

  const fieldDirtyStyle = (isDirty: boolean): Record<string, unknown> => isDirty ? {
    '& .MuiOutlinedInput-root': { borderColor: 'primary.main', boxShadow: 'inset 2px 0 0 currentColor' },
  } : {};

  const titleNode = (
    <Box sx={{ minWidth: 0 }}>
      {allIds.length > 1 ? (
        <>
          <Stack direction="row" spacing={0.75} sx={{ alignItems: 'center' }}>
            <Tooltip title="Previous invoice">
              <span>
                <IconButton size="small" onClick={() => handleNavigate(-1)} disabled={!hasPrev}>
                  <ArrowBackIcon fontSize="small" />
                </IconButton>
              </span>
            </Tooltip>
            <Typography variant="subtitle1" sx={{ fontWeight: 700 }}>
              Invoice {currentIdx + 1} of {allIds.length}
            </Typography>
            <Tooltip title="Next invoice">
              <span>
                <IconButton size="small" onClick={() => handleNavigate(1)} disabled={!hasNext}>
                  <ArrowForwardIcon fontSize="small" />
                </IconButton>
              </span>
            </Tooltip>
          </Stack>
          {inv && (
            <Typography variant="caption" color="text.secondary" sx={{ display: 'block' }}>
              #{inv.docNumber || inv.id}
            </Typography>
          )}
        </>
      ) : (
        <Typography variant="subtitle1" sx={{ fontWeight: 700 }}>
          {inv ? `Invoice #${inv.docNumber || inv.id}` : 'Invoice'}
        </Typography>
      )}
      {inv && (
        <Typography variant="caption" color="text.secondary">{inv.customerName}</Typography>
      )}
    </Box>
  );

  return (
    <FullScreenModal
      open={open}
      onClose={handleClose}
      title={titleNode}
      ariaLabel={inv ? `Invoice #${inv.docNumber || inv.id}` : 'Invoice'}
      data-testid="invoice-detail-drawer"
    >
        {loading && (
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, py: 1, color: 'text.secondary' }}>
            <CircularProgress size={18} />
            <Typography variant="body2">Loading…</Typography>
          </Box>
        )}
        {error && (
          <Typography sx={{ py: 1, color: 'error.main', fontSize: '0.875rem' }}>
            Failed to load invoice: {error}
          </Typography>
        )}
        {inv && !loading && (
          <>
            {/* Meta grid */}
            <Box sx={{ mx: -3, px: 3, py: 2.5, borderBottom: '1px solid', borderColor: 'divider' }}>
              <Box sx={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 1.5 }}>
                {([
                  { label: 'Invoice date', value: fmtDate(inv.txnDate) },
                  { label: 'Balance due',  value: formatCurrency(inv.balance), big: true },
                  { label: 'Due date',     value: fmtDate(inv.dueDate), err: invoiceStatus(inv) === 'overdue' },
                  { label: 'Total',        value: formatCurrency(inv.totalAmt) },
                ] as Array<{ label: string; value: string; big?: boolean; err?: boolean }>).map(item => (
                  <Box key={item.label}>
                    <Typography variant="caption" color="text.secondary" sx={{ textTransform: 'uppercase', letterSpacing: '0.05em', fontWeight: 700 }}>
                      {item.label}
                    </Typography>
                    <Typography
                      variant={item.big ? 'body1' : 'body2'}
                      sx={{ fontWeight: item.big ? 800 : 600, color: item.err ? 'error.main' : 'text.primary' }}
                    >
                      {item.value}
                    </Typography>
                  </Box>
                ))}
              </Box>
            </Box>

            {/* Line items */}
            <Box sx={{ mx: -3, px: 3, py: 2.5, borderBottom: '1px solid', borderColor: 'divider' }}>
              <Typography variant="caption" color="text.secondary" sx={{ textTransform: 'uppercase', letterSpacing: '0.05em', fontWeight: 700, mb: 1.5, display: 'block' }}>
                Line items
              </Typography>
              <Table size="small">
                <TableHead>
                  <TableRow>
                    {['Description', 'Qty', 'Unit price', 'Amount'].map((h, i) => (
                      <TableCell key={h} align={i > 0 ? 'right' : 'left'} sx={{ fontWeight: 700, fontSize: '0.72rem', textTransform: 'uppercase', letterSpacing: '0.04em', color: 'text.secondary', ...(i === 0 ? { pl: 0, width: '55%' } : {}), ...(i === 3 ? { pr: 0 } : {}) }}>
                        {h}
                      </TableCell>
                    ))}
                  </TableRow>
                </TableHead>
                <TableBody>
                  {inv.lines
                    .filter(l => l.detailType !== 'SubTotalLineDetail')
                    .map((l, i) => (
                      <TableRow key={i}>
                        <TableCell sx={{ fontSize: '0.8rem', color: 'text.secondary', pl: 0 }}>{l.description || '—'}</TableCell>
                        <TableCell align="right" sx={{ fontSize: '0.8rem', color: 'text.secondary' }}>{l.qty ?? ''}</TableCell>
                        <TableCell align="right" sx={{ fontSize: '0.8rem', color: 'text.secondary' }}>{l.unitPrice != null ? formatCurrency(l.unitPrice) : ''}</TableCell>
                        <TableCell align="right" sx={{ fontSize: '0.8rem', fontWeight: 700, color: 'text.primary', pr: 0 }}>{formatCurrency(l.amount)}</TableCell>
                      </TableRow>
                    ))}
                </TableBody>
                <TableFooter>
                  <TableRow>
                    <TableCell colSpan={3} sx={{ fontWeight: 600, fontSize: '0.8rem', pl: 0, borderTop: '2px solid', borderColor: 'divider' }}>Total</TableCell>
                    <TableCell align="right" sx={{ fontWeight: 700, fontSize: '0.8rem', pr: 0, borderTop: '2px solid', borderColor: 'divider' }}>{formatCurrency(inv.totalAmt)}</TableCell>
                  </TableRow>
                </TableFooter>
              </Table>
            </Box>

            {/* Edit section (admin only) */}
            {isAdmin && (
              <Box sx={{ mx: -3, px: 3, py: 2.5, borderBottom: '1px solid', borderColor: 'divider' }}>
                <Typography variant="caption" color="text.secondary" sx={{ textTransform: 'uppercase', letterSpacing: '0.05em', fontWeight: 700, mb: 1.5, display: 'block' }}>
                  Edit invoice
                </Typography>
                <Box sx={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 1.5, mb: 1.5 }}>
                  <TextField
                    label="Due date"
                    type="date"
                    size="small"
                    value={edit.due}
                    onChange={e => setEdit(prev => ({ ...prev, due: e.target.value, dirty: true }))}
                    slotProps={{ inputLabel: { shrink: true } }}
                    sx={fieldDirtyStyle(isDueChanged)}
                  />
                  <TextField
                    label="Customer email"
                    type="email"
                    size="small"
                    value={edit.email}
                    onChange={e => setEdit(prev => ({ ...prev, email: e.target.value, dirty: true }))}
                    placeholder="customer@example.com"
                    sx={fieldDirtyStyle(isEmailChanged)}
                  />
                  <TextField
                    label="Message on invoice"
                    multiline
                    rows={2}
                    size="small"
                    value={edit.memo}
                    onChange={e => setEdit(prev => ({ ...prev, memo: e.target.value, dirty: true }))}
                    placeholder="Thank you for your business"
                    sx={{ gridColumn: '1 / -1', ...fieldDirtyStyle(isMemoChanged) }}
                  />
                </Box>
                <Stack direction="row" spacing={1} sx={{ alignItems: 'center' }}>
                  <Button variant="contained" size="small" onClick={handleSave} disabled={saving}>
                    {saving ? 'Saving…' : 'Save changes'}
                  </Button>
                  {edit.dirty && (
                    <Button variant="outlined" size="small" onClick={handleDiscard} color="inherit">
                      Discard
                    </Button>
                  )}
                  {saveMsg && (
                    <Typography variant="caption" sx={{ color: saveMsg.ok ? 'success.main' : 'error.main' }}>
                      {saveMsg.text}
                    </Typography>
                  )}
                </Stack>
              </Box>
            )}

            {/* Actions */}
            <Box sx={{ mx: -3, px: 3, py: 2.5 }}>
              <Typography variant="caption" color="text.secondary" sx={{ textTransform: 'uppercase', letterSpacing: '0.05em', fontWeight: 700, mb: 1.5, display: 'block' }}>
                Actions
              </Typography>
              <Stack direction="row" spacing={1} sx={{ flexWrap: 'wrap' }}>
                <Button
                  variant="outlined"
                  size="small"
                  startIcon={<DownloadIcon />}
                  component="a"
                  href={`/api/quickbooks/invoice/${inv.id}/pdf`}
                  target="_blank"
                  download={`invoice-${inv.docNumber || inv.id}.pdf`}
                  color="inherit"
                >
                  Download PDF
                </Button>
                {isAdmin && (
                  <Button
                    variant="outlined"
                    size="small"
                    startIcon={<EmailIcon />}
                    onClick={handleSend}
                    disabled={sending}
                    color="inherit"
                  >
                    {sending ? 'Sending…' : 'Send to customer'}
                  </Button>
                )}
              </Stack>
              {saveMsg && !isAdmin && (
                <Typography variant="caption" sx={{ color: saveMsg.ok ? 'success.main' : 'error.main', mt: 1, display: 'block' }}>
                  {saveMsg.text}
                </Typography>
              )}
            </Box>
          </>
        )}
    </FullScreenModal>
  );
}
